    def load_history_records(self):
        """加载历史记录到列表"""
        self.history_list_widget.clear()
        history = HistoryManager.load_history()
        
        for record in history:
            timestamp = record.get('timestamp', '')
            filename = record.get('source_file', '未知文件')
            status = record.get('status', 'unknown')
            service = record.get('service', '')
            
            # 格式化显示文本
            if timestamp:
                from datetime import datetime
                try:
                    dt = datetime.fromisoformat(timestamp)
                    time_str = dt.strftime('%Y-%m-%d %H:%M')
                except:
                    time_str = timestamp[:16]
            else:
                time_str = '未知时间'
            
            status_icon = '✓' if status == 'success' else '✗'
            item_text = f"{status_icon} {time_str} | {filename} | {service}"
            
            item = QListWidgetItem(item_text)
            item.setData(Qt.UserRole, record)  # 存储完整记录
            self.history_list_widget.addItem(item)
    
    def on_history_item_changed(self, current, previous):
        """历史记录选中项改变（200ms 防抖，避免快速切换卡顿）"""
        if current is None:
            return
        self._pending_history_item = current
        if not hasattr(self, '_history_debounce'):
            self._history_debounce = QTimer(self)
            self._history_debounce.setSingleShot(True)
            self._history_debounce.timeout.connect(self._apply_history_change)
        self._history_debounce.start(200)

    def _apply_history_change(self):
        """防抖后实际执行历史记录切换"""
        current = getattr(self, '_pending_history_item', None)
        if current is None:
            return
        record = current.data(Qt.UserRole)
        self.current_history_record = record

        # 显示详情（HTML 卡片式）
        status = record.get('status', '未知')
        status_color = '#00B42A' if status == 'success' else '#F53F3F'
        status_text = '成功' if status == 'success' else '失败'
        filename = record.get('source_file', '未知')
        service = record.get('service', '未知')
        lang = f"{record.get('lang_from', '?')} → {record.get('lang_to', '?')}"
        timestamp = record.get('timestamp', '')
        if timestamp:
            try:
                from datetime import datetime
                dt = datetime.fromisoformat(timestamp)
                timestamp = dt.strftime('%m-%d %H:%M')
            except:
                timestamp = timestamp[:16]

        duration = record.get('duration', '')
        duration_str = f" | {duration}秒" if duration else ""

        html = (
            f"<div style='font-family:Microsoft YaHei;word-wrap:break-word;'>"
            f"<b style='font-size:15px;'>{filename}</b><br/>"
            f"<span style='color:{status_color};font-weight:bold;font-size:15px;'>{status_text}</span>"
            f"<span style='font-size:15px;'> | {service} | {lang}{duration_str}</span><br/>"
            f"<span style='color:#888;font-size:13px;'>{timestamp}</span>"
            f"</div>"
        )
        if record.get('error_message'):
            html += f"<br/><span style='color:#F53F3F;font-size:13px;'>错误: {record['error_message'][:100]}</span>"

        self.history_detail_label.setText(html)

        # 自动预览：使用当前全局预览模式
        self.auto_preview_current()

    def set_preview_mode_and_show(self, mode):
        """设置全局预览模式并预览（用户点击预览按钮时调用）"""
        self.history_preview_mode = mode
        self._update_preview_btn_style()
        self.preview_history_file(mode)

    def _update_preview_btn_style(self):
        """高亮当前选中的预览模式按钮"""
        active = "QPushButton { background-color: #165DFF; color: white; font-weight: bold; border-radius: 3px; padding: 4px; }"
        normal = "QPushButton { padding: 4px; }"
        self.preview_mono_btn.setStyleSheet(active if self.history_preview_mode == 'mono' else normal)
        self.preview_dual_btn.setStyleSheet(active if self.history_preview_mode == 'dual' else normal)
        self.preview_side_btn.setStyleSheet(active if self.history_preview_mode == 'side_by_side' else normal)

    def auto_preview_current(self):
        """根据当前全局预览模式自动预览选中的历史文件"""
        if not self.current_history_record:
            return
        output_files = self.current_history_record.get('output_files', {})
        file_path = output_files.get(self.history_preview_mode, '')

        if file_path and os.path.exists(file_path):
            self.preview_widget.load_pdf(file_path)
        else:
            # 当前模式的文件不存在，清空预览
            self.preview_widget.clear()
    
    def preview_history_file(self, file_type):
        """预览历史记录的输出文件"""
        if not self.current_history_record:
            QMessageBox.warning(self, "警告", "请先选择一条历史记录")
            return
        
        output_files = self.current_history_record.get('output_files', {})
        file_path = output_files.get(file_type, '')
        
        if not file_path:
            QMessageBox.warning(self, "警告", f"该记录没有{file_type}版本的输出文件")
            return
        
        if not os.path.exists(file_path):
            reply = QMessageBox.question(
                self, "文件不存在",
                f"输出文件不存在:\n{file_path}\n\n是否从历史记录中移除此记录?",
                QMessageBox.Yes | QMessageBox.No
            )
            if reply == QMessageBox.Yes:
                self.delete_history_record()
            return
        
        # 在右侧预览区域加载文件
        self.preview_widget.load_pdf(file_path)
    
    def open_history_file(self):
        """在外部程序中打开历史记录文件"""
        if not self.current_history_record:
            QMessageBox.warning(self, "警告", "请先选择一条历史记录")
            return
        
        output_files = self.current_history_record.get('output_files', {})
        
        # 优先打开并排版,其次双语版,最后单语版
        for file_type in ['side_by_side', 'dual', 'mono']:
            file_path = output_files.get(file_type, '')
            if file_path and os.path.exists(file_path):
                os.startfile(file_path)
                return
        
        QMessageBox.warning(self, "警告", "所有输出文件都不存在")
    
    def delete_history_record(self):
        """删除选中的历史记录"""
        if not self.current_history_record:
            QMessageBox.warning(self, "警告", "请先选择一条历史记录")
            return
        
        reply = QMessageBox.question(
            self, "确认删除",
            "确定要删除这条历史记录吗?",
            QMessageBox.Yes | QMessageBox.No
        )
        
        if reply == QMessageBox.Yes:
            record_id = self.current_history_record.get('id')
            HistoryManager.delete_record(record_id)
            self.current_history_record = None
            self.history_detail_label.setText("选择一条记录查看详情")
            self.load_history_records()
    
    def clear_all_history(self):
        """清空所有历史记录"""
        reply = QMessageBox.question(
            self, "确认清空",
            "确定要清空所有历史记录吗?\n此操作不可恢复!",
            QMessageBox.Yes | QMessageBox.No
        )
        
        if reply == QMessageBox.Yes:
            HistoryManager.clear_history()
            self.current_history_record = None
            self.history_detail_label.setText("选择一条记录查看详情")
            self.load_history_records()
    
    def load_saved_config(self):
        """加载保存的配置"""
        config = UserConfigManager.load_config()
        if not config:
            return
        
        # 恢复翻译服务
        if 'service' in config:
            index = self.service_combo.findText(config['service'])
            if index >= 0:
                self.service_combo.setCurrentIndex(index)
        
        # 恢复源语言
        if 'lang_from' in config:
            index = self.lang_from_combo.findText(config['lang_from'])
            if index >= 0:
                self.lang_from_combo.setCurrentIndex(index)
        
        # 恢复目标语言
        if 'lang_to' in config:
            index = self.lang_to_combo.findText(config['lang_to'])
            if index >= 0:
                self.lang_to_combo.setCurrentIndex(index)
        
        # 恢复页面范围
        if 'page_range' in config:
            index = self.page_combo.findText(config['page_range'])
            if index >= 0:
                self.page_combo.setCurrentIndex(index)
        
        # 恢复输出模式
        if 'output_mode' in config:
            index = self.output_mode_combo.findText(config['output_mode'])
            if index >= 0:
                self.output_mode_combo.setCurrentIndex(index)
        
        # 恢复线程数
        if 'threads' in config:
            self.threads_spin.setValue(config['threads'])
        
        # 恢复高级选项
        if 'skip_subset_fonts' in config:
            self.skip_fonts_check.setChecked(config['skip_subset_fonts'])
        
        if 'ignore_cache' in config:
            self.ignore_cache_check.setChecked(config['ignore_cache'])
        
        if 'vfont' in config:
            self.vfont_edit.setText(config['vfont'])

        if 'prompt' in config and config['prompt']:
            self.prompt_edit.setPlainText(config['prompt'])

        if 'glossary' in config and config['glossary']:
            self.glossary_edit.setPlainText(config['glossary'])

        # 恢复 Zotero 联动配置
        if HAS_ZOTERO and hasattr(self, 'zotero_mono_cb'):
            if 'zotero_side_by_side' in config:
                self.zotero_side_by_side_cb.setChecked(config['zotero_side_by_side'])
            if 'zotero_bilingual' in config:
                self.zotero_bilingual_cb.setChecked(config['zotero_bilingual'])
            if 'zotero_mono' in config:
                self.zotero_mono_cb.setChecked(config['zotero_mono'])
            if 'zotero_keep_copy' in config:
                self.zotero_keep_copy_cb.setChecked(config['zotero_keep_copy'])

        # 恢复 API 配置（解码敏感信息）
        if 'api_configs' in config:
            for env_name, encoded_value in config['api_configs'].items():
                if env_name in self.api_inputs:
                    decoded_value = UserConfigManager.decode_sensitive(encoded_value)
                    self.api_inputs[env_name].setText(decoded_value)
    
    def save_current_config(self):
        """保存当前配置"""
        config = {
            'service': self.service_combo.currentText(),
            'lang_from': self.lang_from_combo.currentText(),
            'lang_to': self.lang_to_combo.currentText(),
            'page_range': self.page_combo.currentText(),
            'output_mode': self.output_mode_combo.currentText(),
            'threads': self.threads_spin.value(),
            'skip_subset_fonts': self.skip_fonts_check.isChecked(),
            'ignore_cache': self.ignore_cache_check.isChecked(),
            'vfont': self.vfont_edit.text(),
            'prompt': self.prompt_edit.toPlainText(),
            'glossary': self.glossary_edit.toPlainText(),
            'api_configs': {},
        }
        # Zotero 配置
        if HAS_ZOTERO and hasattr(self, 'zotero_mono_cb'):
            config['zotero_side_by_side'] = self.zotero_side_by_side_cb.isChecked()
            config['zotero_bilingual'] = self.zotero_bilingual_cb.isChecked()
            config['zotero_mono'] = self.zotero_mono_cb.isChecked()
            config['zotero_keep_copy'] = self.zotero_keep_copy_cb.isChecked()
        
        # 保存 API 配置（编码敏感信息）
        for env_name, edit in self.api_inputs.items():
            value = edit.text()
            if value:
                encoded_value = UserConfigManager.encode_sensitive(value)
                config['api_configs'][env_name] = encoded_value
        
        UserConfigManager.save_config(config)
    
    def connect_auto_save_signals(self):
        """连接信号以自动保存配置"""
        # 当设置改变时自动保存
        self.service_combo.currentTextChanged.connect(self.save_current_config)
        self.lang_from_combo.currentTextChanged.connect(self.save_current_config)
        self.lang_to_combo.currentTextChanged.connect(self.save_current_config)
        self.page_combo.currentTextChanged.connect(self.save_current_config)
        self.output_mode_combo.currentTextChanged.connect(self.save_current_config)
        self.threads_spin.valueChanged.connect(self.save_current_config)
        self.skip_fonts_check.stateChanged.connect(self.save_current_config)
        self.ignore_cache_check.stateChanged.connect(self.save_current_config)
        self.vfont_edit.textChanged.connect(self.save_current_config)
        # Zotero 联动自动保存
        if HAS_ZOTERO and hasattr(self, 'zotero_mono_cb'):
            self.zotero_side_by_side_cb.stateChanged.connect(self.save_current_config)
            self.zotero_bilingual_cb.stateChanged.connect(self.save_current_config)
            self.zotero_mono_cb.stateChanged.connect(self.save_current_config)
            self.zotero_keep_copy_cb.stateChanged.connect(self.save_current_config)

        # API 配置输入框失去焦点时保存
        for edit in self.api_inputs.values():
            edit.editingFinished.connect(self.save_current_config)
    
    def _save_recent_file(self, file_path):
        """保存文件到最近打开列表"""
        config = UserConfigManager.load_config()
        recent = config.get('recent_files', [])
        if file_path in recent:
            recent.remove(file_path)
        recent.insert(0, file_path)
        recent = recent[:10]
        config['recent_files'] = recent
        UserConfigManager.save_config(config)

    def _detect_pdf_info(self, file_path):
        """自动检测 PDF 的源语言和是否为扫描件"""
        if not HAS_PYMUPDF:
            return
        try:
            doc = fitz.open(file_path)
            # 提取前几页文字
            text = ""
            pages_with_text = 0
            for i in range(min(5, doc.page_count)):
                page_text = doc[i].get_text().strip()
                text += page_text + " "
                if len(page_text) > 30:
                    pages_with_text += 1
            doc.close()

            # 自动检测扫描件
            if pages_with_text == 0 and doc.page_count > 0:
                if not self.ocr_mode_check.isChecked():
                    self.ocr_mode_check.setChecked(True)
                    self.status_label.setText("检测到纯扫描件，已自动开启 OCR")

            # 自动检测语言（基于字符统计）
            if len(text.strip()) > 20:
                cjk = sum(1 for c in text if '\u4e00' <= c <= '\u9fff')
                jp = sum(1 for c in text if '\u3040' <= c <= '\u30ff')
                kr = sum(1 for c in text if '\uac00' <= c <= '\ud7af')
                ru = sum(1 for c in text if '\u0400' <= c <= '\u04ff')
                latin = sum(1 for c in text if 'a' <= c.lower() <= 'z')
                total = max(1, cjk + jp + kr + ru + latin)

                detected = None
                if jp / total > 0.05 and jp > 10:
                    # 有假名就是日文（日文混用大量汉字，必须优先检测假名）
                    detected = "Japanese"
                elif cjk / total > 0.3 and jp <= 10:
                    detected = "简体中文"
                elif kr / total > 0.2:
                    detected = "Korean"
                elif ru / total > 0.2:
                    detected = "Russian"
                elif latin / total > 0.3:
                    detected = "English"

                if detected:
                    idx = self.lang_from_combo.findText(detected)
                    if idx >= 0:
                        self.lang_from_combo.setCurrentIndex(idx)
                        # 自动设目标语言（中文→英文，其他→中文）
                        if detected == "简体中文":
                            to_idx = self.lang_to_combo.findText("English")
                        else:
                            to_idx = self.lang_to_combo.findText("简体中文")
                        if to_idx >= 0:
                            self.lang_to_combo.setCurrentIndex(to_idx)
        except Exception:
            pass

    def browse_file(self):
        file_paths, _ = QFileDialog.getOpenFileNames(
            self, "选择 PDF 文件", "", "PDF 文件 (*.pdf)"
        )
        if file_paths:
            for fp in file_paths:
                if fp not in self.batch_files:
                    self.batch_files.append(fp)
                    self.file_list_widget.addItem(os.path.basename(fp))
            self.update_file_count()
            # 预览最后一个文件
            self.current_file = file_paths[-1]
            self.setWindowTitle(f"pdf2zh 桌面版 v2.2.4 - {os.path.basename(self.current_file)}")
            if HAS_PYMUPDF:
                self.preview_widget.load_pdf(self.current_file)
            self._detect_pdf_info(self.current_file)
            self._check_zotero_source()

    def add_batch_folder(self):
        """添加文件夹中的所有 PDF（递归扫描子目录）"""
        folder = QFileDialog.getExistingDirectory(self, "选择文件夹")
        if folder:
            pdf_files = sorted(Path(folder).rglob("*.pdf"))
            added = 0
            for f in pdf_files:
                f_str = str(f)
                if f_str not in self.batch_files:
                    self.batch_files.append(f_str)
                    self.file_list_widget.addItem(f.name)
                    added += 1
            self.update_file_count()
            if added and pdf_files:
                self.current_file = str(pdf_files[-1])
                if HAS_PYMUPDF:
                    self.preview_widget.load_pdf(self.current_file)
                self._detect_pdf_info(self.current_file)
                self._check_zotero_source()
    
    def remove_selected_files(self):
        """移除选中的文件（倒序删除避免索引偏移）"""
        selected_items = self.file_list_widget.selectedItems()
        # 倒序删除避免索引偏移问题
        for item in reversed(selected_items):
            row = self.file_list_widget.row(item)
            self.file_list_widget.takeItem(row)
            if row < len(self.batch_files):
                del self.batch_files[row]
        self.update_file_count()
    
    def clear_batch_files(self):
        """清空文件列表和当前文件引用，恢复初始状态"""
        self.batch_files.clear()
        self.file_list_widget.clear()
        self.current_file = None
        self.update_file_count()
        self._zotero_hint.setText("")

    def update_file_count(self):
        """更新文件数量显示"""
        count = len(self.batch_files)
        if count == 0:
            self.file_count_label.setText("拖入 PDF 或点击选择")
        else:
            self.file_count_label.setText(f"已选择 {count} 个文件  |  支持拖入文件或文件夹")
    
    @staticmethod
    def _get_greeting() -> str:
        """从 config/greetings.json 读取标语，支持大量随机"""
        from datetime import datetime
        import random
        now = datetime.now()
        hour = now.hour
        m, d = now.month, now.day

        # 加载标语库
        greetings = {}
        try:
            gpath = os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', '..', 'config', 'greetings.json')
            if not os.path.exists(gpath):
                gpath = os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', '..', '..', 'config', 'greetings.json')
            if os.path.exists(gpath):
                with open(gpath, 'r', encoding='utf-8') as f:
                    greetings = json.load(f)
        except Exception:
            pass

        # 节日
        key = f"{m:02d}-{d:02d}"
        holidays = greetings.get('holidays', {})
        if key in holidays:
            msgs = holidays[key] if isinstance(holidays[key], list) else [holidays[key]]
            return f"~ {random.choice(msgs)} ~"
        # 春节
        if m == 2 and 10 <= d <= 17:
            msgs = greetings.get('spring_festival', ['新春快乐'])
            return f"~ {random.choice(msgs)} ~"

        # 时段
        time_keys = {
            (0, 5): 'night_0_5', (5, 8): 'morning_5_8', (8, 12): 'forenoon_8_12',
            (12, 14): 'noon_12_14', (14, 18): 'afternoon_14_18',
            (18, 22): 'evening_18_22', (22, 24): 'late_night_22_24',
        }
        for (start, end), k in time_keys.items():
            if start <= hour < end:
                msgs = greetings.get(k, [])
                if msgs:
                    return f"~ {random.choice(msgs)} ~"

        # 通用兜底
        msgs = greetings.get('universal', ['知识无国界'])
        return f"~ {random.choice(msgs)} ~"

