        # 内置模板
        for name in ["学术论文风格", "口语化/易懂风格", "保留专业术语", "医学/法律专业", "简洁摘要式"]:
            self.prompt_preset_combo.addItem(name)
        # 用户自定义模板
        config = UserConfigManager.load_config()
        user_templates = config.get('user_prompt_templates', {})
        if user_templates:
            self.prompt_preset_combo.insertSeparator(self.prompt_preset_combo.count())
            for name in user_templates:
                self.prompt_preset_combo.addItem(f"[自定义] {name}")

